#!/usr/bin/env bun
// aqc — command-line front-end for @alaq/graph.
//
// Two entry points:
//   1. Default compile mode — `aqc <input.aql> [-o <out.ir.json>]`
//      Reads a single .aql, runs parseSource, emits IR JSON or diagnostics.
//   2. Generator mode — `aqc gen <target> <input.aql> [-o <out-dir>]`
//      Compiles the .aql, then invokes the requested generator
//      (`@alaq/graph-<target>`) and writes every generated file under
//      `<out-dir>`, preserving the relative path shape returned by the
//      generator. One CLI for every consumer build-script.
//
// Designed for build pipelines and smoke-tests: consumers can invoke
//   `bunx aqc schema.aql -o schema.ir.json`           (compile)
//   `bunx aqc gen axum schema.aql -o generated/rs/`   (codegen)
// from a package.json script instead of hand-rolling a runner.
//
// Usage:
//   aqc <input.aql> [-o <out.ir.json>] [--pretty] [--json]
//   aqc gen <target> <input.aql> [-o <out-dir>] [--namespace <ns>]
//                                 [--no-header] [--json]
//   aqc --help | -h
//   aqc gen --help
//
// Targets for `gen`: axum, tauri-rs, tauri, zenoh, link-state, link-server.
//
// Exit codes:
//   0  success (IR / files produced, zero errors; warnings allowed)
//   1  compile error or generator error (diagnostics on stderr)
//   2  usage error (bad argv, missing input, missing generator pkg, I/O failure)

import { parseSource } from '../src/index'
import type { Diagnostic, IR } from '../src/types'

// ────────────────────────────────────────────────────────────────
// Generator target registry
// ────────────────────────────────────────────────────────────────

/**
 * Known generator targets. The CLI resolves `@alaq/graph-<target>` (and
 * falls back to the sibling path under `packages/` when the package is
 * not installed — useful for in-repo consumers that haven't run
 * `bun install`).
 */
const TARGETS: ReadonlyArray<string> = [
  'axum',
  'tauri-rs',
  'tauri',
  'zenoh',
  'link-state',
  'link-server',
]

interface GeneratorModule {
  generate: (ir: IR, options?: Record<string, unknown>) => GenerateResultLike
}

interface GenerateResultLike {
  files: Array<{ path: string; content: string }>
  diagnostics: Array<{ severity: 'error' | 'warning'; message: string }>
}

// ────────────────────────────────────────────────────────────────
// Help text
// ────────────────────────────────────────────────────────────────

const HELP = `aqc — compile .aql sources and drive @alaq/graph-* generators.

Usage:
  aqc <input.aql> [-o <out.ir.json>] [--pretty] [--json]
  aqc gen <target> <input.aql> [-o <out-dir>] [options]
  aqc --help | -h
  aqc gen --help

Compile mode options:
  -o, --output <path>   Write IR to file instead of stdout.
  --pretty              Pretty-print IR (2-space indent). Default: compact.
  --json                Emit diagnostics as JSON (stderr). Default: human-readable.
  -h, --help            Show this help and exit 0.

Generator targets (for \`aqc gen <target> ...\`):
  axum         — Rust/Axum router, handlers trait, AppState (@alaq/graph-axum)
  tauri-rs     — Rust side of a Tauri v2 app: commands + handlers trait (@alaq/graph-tauri-rs)
  tauri        — TS side of a Tauri v2 app: typed invoke wrappers (@alaq/graph-tauri)
  zenoh        — Rust Zenoh pub/sub + actions module (@alaq/graph-zenoh)
  link-state   — TS reactive bindings for @alaq/link-state (@alaq/graph-link-state)
  link-server  — TS server-side handlers scaffold for @alaq/link (@alaq/graph-link-server)

Examples:
  aqc schema.aql
  aqc schema.aql -o schema.ir.json --pretty
  aqc gen axum arsenal.aql -o generated/rs/
  aqc gen tauri-rs reader.aql -o src-tauri/src/generated/
  aqc gen tauri reader.aql -o ui/src/generated/
  aqc gen --help
`

const HELP_GEN = `aqc gen — invoke an @alaq/graph-* generator on an .aql file.

Usage:
  aqc gen <target> <input.aql> [-o <out-dir>] [options]

Targets:
  axum, tauri-rs, tauri, zenoh, link-state, link-server

Options:
  -o, --output <dir>    Output directory for generated files. Default: ./generated
  --namespace <ns>      Emit only the given namespace. Default: every namespace in IR.
  --no-header           Suppress the AUTOGENERATED file banner.
  --json                Emit diagnostics as JSON (stderr). Default: human-readable.
  -h, --help            Show this help and exit 0.

Behavior:
  - The generator runs on the fully-compiled IR. Compile errors abort with exit 1
    before any files are written.
  - Generator warnings go to stderr; generator errors abort with exit 1 and no
    files are written.
  - The output directory is created if missing. Paths returned by the generator
    are joined onto <out-dir> verbatim; nested namespaces land in subdirectories.
  - If the \`@alaq/graph-<target>\` package is not installed, aqc falls back to
    the sibling path inside the alak monorepo checkout. Outside the monorepo,
    install the generator: \`bun add @alaq/graph-<target>\`.

Examples:
  aqc gen axum arsenal.aql -o generated/rs/
  aqc gen tauri-rs reader.aql -o ../src-tauri/src/generated/
  aqc gen tauri reader.aql -o ../ui/src/generated/
  aqc gen link-state schema.aql -o src/generated/ --no-header
`

// ────────────────────────────────────────────────────────────────
// Helpers — shared with both modes
// ────────────────────────────────────────────────────────────────

function fail(msg: string, code = 2): never {
  process.stderr.write(`aqc: ${msg}\n`)
  process.exit(code)
}

function formatDiagnostic(d: Diagnostic): string {
  const loc = d.file ? `${d.file}:${d.line}:${d.column}` : `${d.line}:${d.column}`
  const sev = d.severity.toUpperCase()
  return `${sev} ${d.code} ${loc}  ${d.message}`
}

async function readInput(path: string): Promise<string> {
  try {
    if (typeof (globalThis as any).Bun !== 'undefined') {
      return await (globalThis as any).Bun.file(path).text()
    }
    const fs = await import('node:fs/promises')
    return await fs.readFile(path, 'utf8')
  } catch (e: any) {
    fail(`cannot read ${path}: ${e?.message ?? e}`)
  }
}

async function writeOutput(path: string, content: string): Promise<void> {
  try {
    if (typeof (globalThis as any).Bun !== 'undefined') {
      await (globalThis as any).Bun.write(path, content)
      return
    }
    const fs = await import('node:fs/promises')
    await fs.writeFile(path, content, 'utf8')
  } catch (e: any) {
    fail(`cannot write ${path}: ${e?.message ?? e}`)
  }
}

async function mkdirp(dir: string): Promise<void> {
  const fs = await import('node:fs/promises')
  await fs.mkdir(dir, { recursive: true })
}

// ────────────────────────────────────────────────────────────────
// Compile mode — preserves W1 behavior verbatim
// ────────────────────────────────────────────────────────────────

interface CompileArgs {
  input: string
  output?: string
  pretty: boolean
  json: boolean
}

function parseCompileArgs(argv: string[]): CompileArgs | 'help' {
  let input: string | undefined
  let output: string | undefined
  let pretty = false
  let json = false

  for (let i = 0; i < argv.length; i++) {
    const a = argv[i]
    if (a === '-h' || a === '--help') return 'help'
    if (a === '--pretty') {
      pretty = true
      continue
    }
    if (a === '--json') {
      json = true
      continue
    }
    if (a === '-o' || a === '--output') {
      const next = argv[i + 1]
      if (!next) fail(`${a} requires a path argument`)
      output = next
      i++
      continue
    }
    if (a.startsWith('--output=')) {
      output = a.slice('--output='.length)
      continue
    }
    if (a.startsWith('-') && a !== '-') {
      fail(`unknown option: ${a}`)
    }
    if (input !== undefined) {
      fail(`unexpected extra argument: ${a}`)
    }
    input = a
  }

  if (!input) fail('missing input file (run `aqc --help` for usage)')
  return { input, output, pretty, json }
}

async function runCompile(argv: string[]): Promise<never> {
  const parsed = parseCompileArgs(argv)
  if (parsed === 'help') {
    process.stdout.write(HELP)
    process.exit(0)
  }

  const { input, output, pretty, json } = parsed

  const source = await readInput(input)
  const { ir, diagnostics } = parseSource(source, input)

  const errors = diagnostics.filter(d => d.severity === 'error')
  const warnings = diagnostics.filter(d => d.severity === 'warning')

  if (warnings.length > 0) {
    if (json) {
      process.stderr.write(JSON.stringify(warnings) + '\n')
    } else {
      for (const d of warnings) process.stderr.write(formatDiagnostic(d) + '\n')
    }
  }

  if (errors.length > 0) {
    if (json) {
      process.stderr.write(JSON.stringify(errors) + '\n')
    } else {
      for (const d of errors) process.stderr.write(formatDiagnostic(d) + '\n')
      process.stderr.write(`aqc: ${errors.length} error(s) — IR not emitted\n`)
    }
    process.exit(1)
  }

  if (!ir) {
    fail('no IR produced and no errors reported — compiler invariant violated', 1)
  }

  const payload = pretty ? JSON.stringify(ir, null, 2) : JSON.stringify(ir)

  if (output) {
    await writeOutput(output, payload + (pretty ? '\n' : ''))
  } else {
    process.stdout.write(payload)
    if (pretty) process.stdout.write('\n')
  }

  process.exit(0)
}

// ────────────────────────────────────────────────────────────────
// Generator mode
// ────────────────────────────────────────────────────────────────

interface GenArgs {
  target: string
  input: string
  outDir: string
  namespace?: string
  header: boolean
  json: boolean
}

function parseGenArgs(argv: string[]): GenArgs | 'help' {
  let target: string | undefined
  let input: string | undefined
  let outDir: string | undefined
  let namespace: string | undefined
  let header = true
  let json = false

  const positional: string[] = []

  for (let i = 0; i < argv.length; i++) {
    const a = argv[i]
    if (a === '-h' || a === '--help') return 'help'
    if (a === '--no-header') {
      header = false
      continue
    }
    if (a === '--json') {
      json = true
      continue
    }
    if (a === '-o' || a === '--output') {
      const next = argv[i + 1]
      if (!next) fail(`${a} requires a path argument`)
      outDir = next
      i++
      continue
    }
    if (a.startsWith('--output=')) {
      outDir = a.slice('--output='.length)
      continue
    }
    if (a === '--namespace') {
      const next = argv[i + 1]
      if (!next) fail(`${a} requires an argument`)
      namespace = next
      i++
      continue
    }
    if (a.startsWith('--namespace=')) {
      namespace = a.slice('--namespace='.length)
      continue
    }
    if (a.startsWith('-') && a !== '-') {
      fail(`unknown option: ${a}`)
    }
    positional.push(a)
  }

  if (positional.length === 0) {
    fail('missing target (run `aqc gen --help` for usage)')
  }
  target = positional[0]
  if (!TARGETS.includes(target)) {
    fail(
      `unknown target "${target}". Known: ${TARGETS.join(', ')} ` +
        `(run \`aqc gen --help\` for usage)`,
    )
  }

  if (positional.length < 2) {
    fail('missing input .aql file (run `aqc gen --help` for usage)')
  }
  if (positional.length > 2) {
    fail(`unexpected extra argument: ${positional[2]}`)
  }
  input = positional[1]

  return {
    target,
    input,
    outDir: outDir ?? 'generated',
    namespace,
    header,
    json,
  }
}

/**
 * Resolve and dynamic-import the generator module for `target`.
 * Strategy:
 *   1. Try `@alaq/graph-<target>` — works when the generator is installed
 *      in the consumer's node_modules.
 *   2. Fall back to the sibling path inside the alak monorepo
 *      (`../../graph-<target>/src/index.ts` relative to this script).
 *      Useful for in-repo consumers who import generators by relative path
 *      today and haven't wired up node_modules.
 * Throws with a structured hint if neither resolves.
 */
async function loadGenerator(target: string): Promise<GeneratorModule> {
  const pkgName = `@alaq/graph-${target}`
  let firstErr: unknown
  try {
    const mod = (await import(pkgName)) as GeneratorModule
    if (typeof mod.generate !== 'function') {
      fail(`generator "${pkgName}" does not export a \`generate\` function`)
    }
    return mod
  } catch (e) {
    firstErr = e
  }

  // Sibling-path fallback. `bin/aqc.ts` → `packages/graph/bin/` →
  // `packages/graph-<target>/src/index.ts`.
  const path = await import('node:path')
  const scriptDir =
    typeof (import.meta as any).dir === 'string'
      ? (import.meta as any).dir
      : path.dirname(new URL(import.meta.url).pathname.replace(/^\/([A-Za-z]:)/, '$1'))
  const siblingPath = path.resolve(scriptDir, '..', '..', `graph-${target}`, 'src', 'index.ts')

  try {
    const mod = (await import(siblingPath)) as GeneratorModule
    if (typeof mod.generate !== 'function') {
      fail(`generator at ${siblingPath} does not export a \`generate\` function`)
    }
    return mod
  } catch (e) {
    const msg =
      `generator "${pkgName}" is not installed and sibling path ${siblingPath} ` +
      `could not be imported. Install it: \`bun add ${pkgName}\` ` +
      `(or \`npm install ${pkgName}\`). ` +
      `First error: ${(firstErr as any)?.message ?? firstErr}. ` +
      `Fallback error: ${(e as any)?.message ?? e}.`
    fail(msg)
  }
}

async function runGen(argv: string[]): Promise<never> {
  const parsed = parseGenArgs(argv)
  if (parsed === 'help') {
    process.stdout.write(HELP_GEN)
    process.exit(0)
  }

  const { target, input, outDir, namespace, header, json } = parsed

  // 1. Compile .aql → IR
  const source = await readInput(input)
  const { ir, diagnostics } = parseSource(source, input)

  const parseErrors = diagnostics.filter(d => d.severity === 'error')
  const parseWarnings = diagnostics.filter(d => d.severity === 'warning')

  if (parseWarnings.length > 0) {
    if (json) {
      process.stderr.write(JSON.stringify(parseWarnings) + '\n')
    } else {
      for (const d of parseWarnings) {
        process.stderr.write(formatDiagnostic(d) + '\n')
      }
    }
  }

  if (parseErrors.length > 0) {
    if (json) {
      process.stderr.write(JSON.stringify(parseErrors) + '\n')
    } else {
      for (const d of parseErrors) {
        process.stderr.write(formatDiagnostic(d) + '\n')
      }
      process.stderr.write(
        `aqc: ${parseErrors.length} compile error(s) — generator not run\n`,
      )
    }
    process.exit(1)
  }

  if (!ir) {
    fail('no IR produced and no errors reported — compiler invariant violated', 1)
  }

  // 2. Load generator + invoke
  const gen = await loadGenerator(target)

  // Every shipping generator accepts { namespace, header, ... }.
  // Unknown keys are ignored by each generator's option merge.
  const options: Record<string, unknown> = { header }
  if (namespace !== undefined) options.namespace = namespace

  let result: GenerateResultLike
  try {
    result = gen.generate(ir, options)
  } catch (e: any) {
    fail(`generator "@alaq/graph-${target}" threw: ${e?.message ?? e}`, 1)
  }

  const genErrors = result.diagnostics.filter(d => d.severity === 'error')
  const genWarnings = result.diagnostics.filter(d => d.severity === 'warning')

  if (genWarnings.length > 0) {
    if (json) {
      process.stderr.write(
        JSON.stringify(genWarnings.map(w => ({ severity: w.severity, message: w.message }))) + '\n',
      )
    } else {
      for (const w of genWarnings) {
        process.stderr.write(`WARN [@alaq/graph-${target}]  ${w.message}\n`)
      }
    }
  }

  if (genErrors.length > 0) {
    if (json) {
      process.stderr.write(
        JSON.stringify(genErrors.map(e => ({ severity: e.severity, message: e.message }))) + '\n',
      )
    } else {
      for (const e of genErrors) {
        process.stderr.write(`ERROR [@alaq/graph-${target}]  ${e.message}\n`)
      }
    }
    process.stderr.write(
      `aqc: ${genErrors.length} generator error(s) — no files written\n`,
    )
    process.exit(1)
  }

  // 3. Write files
  const path = await import('node:path')
  await mkdirp(outDir)
  for (const f of result.files) {
    const full = path.join(outDir, f.path)
    await mkdirp(path.dirname(full))
    await writeOutput(full, f.content)
  }

  process.stdout.write(
    `Generated ${result.files.length} file(s) in ${outDir}. ` +
      `Warnings: ${genWarnings.length}.\n`,
  )
  process.exit(0)
}

// ────────────────────────────────────────────────────────────────
// Entry dispatch
// ────────────────────────────────────────────────────────────────

const argv = process.argv.slice(2)

if (argv[0] === 'gen') {
  await runGen(argv.slice(1))
} else {
  await runCompile(argv)
}
